import{_ as r,o as i,c as l,a2 as a}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"🫘 黃豆追蹤日報 — 2026-05-17（週日）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-17.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-17.md"}'),o={name:"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-17.md"};function n(s,t,e,d,g,h){return i(),l("div",null,[...t[0]||(t[0]=[a('<h1 id="🫘-黃豆追蹤日報-—-2026-05-17-週日" tabindex="-1">🫘 黃豆追蹤日報 — 2026-05-17（週日） <a class="header-anchor" href="#🫘-黃豆追蹤日報-—-2026-05-17-週日" aria-label="Permalink to &quot;🫘 黃豆追蹤日報 — 2026-05-17（週日）&quot;">​</a></h1><blockquote><p>查詢時間：2026-05-17 05:00 TST（2026-05-16 21:00 UTC） 報告類型：每日追蹤 ⚠️ CBOT 期貨時段說明：05:00 TST 週日凌晨 = 17:00 ET 週六，黃豆期貨已收盤（最後交易日 5/15 週五）</p></blockquote><hr><h2 id="📊-即時報價" tabindex="-1">📊 即時報價 <a class="header-anchor" href="#📊-即時報價" aria-label="Permalink to &quot;📊 即時報價&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指標</th><th>報價</th><th>日漲跌</th><th>查詢時間</th><th>來源</th></tr></thead><tbody><tr><td>CBOT 黃豆 Jul 2026 (ZS=F)</td><td>1,177 USd/Bu</td><td>-15.50¢ (-1.30%)</td><td>2026-05-15 16:00 ET</td><td>TradingEconomics</td></tr><tr><td>CBOT 黃豆 Nov 2026 (ZSX26)</td><td>~1,165¢（估算）</td><td>—</td><td>2026-05-15</td><td>TradingEconomics</td></tr><tr><td>WTI 原油</td><td>$105.42/桶</td><td>+$4.25 (+4.20%)</td><td>2026-05-15</td><td>TradingEconomics</td></tr><tr><td>Brent 原油</td><td>$109.26/桶</td><td>+$3.46 (+3.26%)</td><td>2026-05-15</td><td>TradingEconomics</td></tr><tr><td>DXY 美元指數</td><td>99.27</td><td>+0.46</td><td>2026-05-15</td><td>TradingEconomics</td></tr><tr><td>尿素</td><td>$577/噸</td><td>+$4.50 (+0.79%)</td><td>2026-05-15</td><td>TradingEconomics</td></tr><tr><td>天然氣 Henry Hub</td><td>$2.96/MMBtu</td><td>+$0.066 (+2.28%)</td><td>2026-05-15</td><td>TradingEconomics</td></tr></tbody></table><blockquote><p><strong>查詢時間（TST）</strong>：2026-05-17 05:00</p></blockquote><hr><h2 id="🔍-敘事延續-川習會後續-—-中國稱「preliminary」-scmp-分析增量有限" tabindex="-1">🔍 敘事延續：川習會後續 — 中國稱「preliminary」+ SCMP 分析增量有限 <a class="header-anchor" href="#🔍-敘事延續-川習會後續-—-中國稱「preliminary」-scmp-分析增量有限" aria-label="Permalink to &quot;🔍 敘事延續：川習會後續 — 中國稱「preliminary」+ SCMP 分析增量有限&quot;">​</a></h2><p><strong>本日核心</strong>：黃豆價格收在 1,177 USd/Bu（-1.30%），連續第二日下跌。週末中國商務部首次公開定性川習會農業成果為「preliminary」，需盡快定案。SCMP 分析師指出 Greer 宣稱的「double-digit billions」多為 2025 年釜山峰會已承諾的 25M 噸/年舊約重包，增量有限。S&amp;P Global 數據顯示年初至今美國對華黃豆銷售年減 48%。但 CNBF 報導市場預期 10% 黃豆關稅將下調，可能允許中國私營壓榨廠恢復採購。荷莫茲海峽方面，伊拉克透露出口暴跌 90%，伊朗提議「管理機制」但細節不明。</p><hr><h2 id="_8-項追蹤指標" tabindex="-1">8 項追蹤指標 <a class="header-anchor" href="#_8-項追蹤指標" aria-label="Permalink to &quot;8 項追蹤指標&quot;">​</a></h2><h3 id="_1-usda-種植進度報告-每週" tabindex="-1">1. USDA 種植進度報告（每週） <a class="header-anchor" href="#_1-usda-種植進度報告-每週" aria-label="Permalink to &quot;1. USDA 種植進度報告（每週）&quot;">​</a></h3><ul><li><strong>種植進度</strong>（截至 5/10）：49% 黃豆已播種（前週 33%），高於五年均值 36%</li><li><strong>出芽率</strong>：20% 已出芽（五年均值 12%）</li><li><strong>WASDE 5/12</strong>：2026/27 終庫存 310M bu（低於預期 ~355M），壓榨 2.75B bu（連續 6 年創紀錄）</li><li><strong>變化</strong>：🟡 種植進度良好 — 下週 expected 60%+ 播種</li><li><strong>查詢時間</strong>：2026-05-12 12:00 ET</li><li>來源：Farm Progress (2026-05-12)、Successful Farming (2026-05-11)</li></ul><h3 id="_2-巴西供應-收割-出口-豐收" tabindex="-1">2. 巴西供應（收割 + 出口 + 豐收） <a class="header-anchor" href="#_2-巴西供應-收割-出口-豐收" aria-label="Permalink to &quot;2. 巴西供應（收割 + 出口 + 豐收）&quot;">​</a></h3><ul><li><strong>巴西收割</strong>：2025/26 年度收割已基本完成</li><li><strong>全球年終庫存</strong>：1.957B 蒲式耳（-185M vs 25/26，但 +35M vs 預期）</li><li><strong>變化</strong>：🟡 無重大變化 — 巴西供應穩定</li><li><strong>查詢時間</strong>：2026-05-13</li><li>來源：USDA WASDE (2026-05-12)</li></ul><h3 id="_3-尿素價格-多單訊號" tabindex="-1">3. 尿素價格 + 多單訊號 <a class="header-anchor" href="#_3-尿素價格-多單訊號" aria-label="Permalink to &quot;3. 尿素價格 + 多單訊號&quot;">​</a></h3><ul><li><strong>尿素</strong>：$577/噸（+0.79%），月跌 19.07% 但年漲 21.79%</li><li><strong>化肥成本</strong>：伊朗戰爭持續推升化肥與柴油成本（PPI 6%）</li><li><strong>變化</strong>：🟡 無重大變化 — 成本持續高檔但尿素月跌 19%</li><li><strong>查詢時間</strong>：2026-05-15</li><li>來源：TradingEconomics (2026-05-15)</li></ul><h3 id="_4-荷莫茲海峽通航狀態" tabindex="-1">4. 荷莫茲海峽通航狀態 <a class="header-anchor" href="#_4-荷莫茲海峽通航狀態" aria-label="Permalink to &quot;4. 荷莫茲海峽通航狀態&quot;">​</a></h3><ul><li>🔴 <strong>持續惡化</strong>：海峽出口暴跌 90%，伊朗提議「管理機制」</li><li><strong>伊拉克</strong>：4 月出口僅 10M 桶（戰前月均 93M），暴跌 90%（MalayMail/Reuters 5/16）</li><li><strong>伊朗 Azizi</strong>（5/16）：將「soon」公布「professional mechanism to manage traffic」，對合規船隻收費</li><li><strong>CENTCOM</strong>：截至 5/16，78 艘商業船被改道，4 艘被扣押</li><li><strong>US Energy Secretary</strong>：海峽將「sometime this summer」重新開放</li><li><strong>影響</strong>：能源成本飆漲 → 農業生產成本上升 → 間接支撐黃豆價格底部</li><li><strong>變化</strong>：🔴 <strong>持續惡化</strong> — 伊拉克出口數據證實海峽實質封閉</li><li><strong>查詢時間</strong>：2026-05-16</li><li>來源：MalayMail/Reuters (2026-05-16)、WION (2026-05-16)、Anadolu (2026-05-16)</li></ul><h3 id="_5-中美貿易-中國進口" tabindex="-1">5. 中美貿易 + 中國進口 <a class="header-anchor" href="#_5-中美貿易-中國進口" aria-label="Permalink to &quot;5. 中美貿易 + 中國進口&quot;">​</a></h3><ul><li>🔴 <strong>關鍵更新</strong>：中國稱協議「preliminary」，SCMP 分析增量有限</li><li><strong>中國商務部</strong>（5/16）：農業/關稅協議為「preliminary」，需「finalised as soon as possible」</li><li><strong>SCMP 分析</strong>：Greer 的「double-digit billions」多為釜山峰會已承諾的 25M 噸/年重包</li><li><strong>S&amp;P Global</strong>：年初至今美國對華黃豆銷售年減 48%</li><li><strong>CNBC</strong>：市場預期 10% 黃豆關稅將下調，允許 private crushers 恢復採購</li><li><strong>Bessent</strong>：稱黃豆「taken care of」，暗示新協議可能聚焦其他品項</li><li><strong>關鍵時間點</strong>：9-10 月美國黃豆收成季，若中國不在此期間增加採購，出口復甦夢碎</li><li><strong>變化</strong>：🔴 <strong>關鍵轉折</strong> — 中國「preliminary」定性降低短期期望</li><li><strong>查詢時間</strong>：2026-05-16</li><li>來源：CNBC (2026-05-16)、SCMP (2026-05-16)、AOL/Reuters (2026-05-16)、S&amp;P Global (2026-05-14)</li></ul><h3 id="_6-天然氣價格" tabindex="-1">6. 天然氣價格 <a class="header-anchor" href="#_6-天然氣價格" aria-label="Permalink to &quot;6. 天然氣價格&quot;">​</a></h3><ul><li><strong>Henry Hub</strong>：$2.96/MMBtu（+2.28%），接近七週高</li><li><strong>EIA 注入</strong>：85 bcf（符合預期），低於去年同期 109 bcf</li><li><strong>供給</strong>：EQT 等削減產出，日產量降至 15 週低</li><li><strong>出口</strong>：LNG 出口從 4 月紀錄 18.8 bcfd 降至 5 月 ~17.0 bcfd（季節性維護）</li><li><strong>變化</strong>：🟡 無重大變化 — 供給偏緊但需求季節性低</li><li><strong>查詢時間</strong>：2026-05-15</li><li>來源：TradingEconomics (2026-05-15)</li></ul><h3 id="_7-聖嬰-拉尼娜氣候風險" tabindex="-1">7. 聖嬰/拉尼娜氣候風險 <a class="header-anchor" href="#_7-聖嬰-拉尼娜氣候風險" aria-label="Permalink to &quot;7. 聖嬰/拉尼娜氣候風險&quot;">​</a></h3><ul><li><strong>變化</strong>：⚪ 本日無重大更新 — 待下季氣候報告</li><li><strong>查詢時間</strong>：2026-05-17</li></ul><h3 id="_8-cbot-價格區間" tabindex="-1">8. CBOT 價格區間 <a class="header-anchor" href="#_8-cbot-價格區間" aria-label="Permalink to &quot;8. CBOT 價格區間&quot;">​</a></h3><ul><li><strong>Jul 2026</strong>：1,177 USd/Bu（-1.30%），本週跌約 3%</li><li><strong>技術面</strong>：從 5/12 WASDE 後高點 ~1,210 回落，支撐 1,150-1,160</li><li>** Nov 2026**：~1,165¢（估算），新農作定價區間</li><li><strong>變化</strong>：🟡 延續跌勢 — 川習會無實質突破 + 通膨壓力</li><li><strong>查詢時間</strong>：2026-05-15</li><li>來源：TradingEconomics (2026-05-15)</li></ul><hr><h2 id="📰-即時新聞-5-條" tabindex="-1">📰 即時新聞（5 條） <a class="header-anchor" href="#📰-即時新聞-5-條" aria-label="Permalink to &quot;📰 即時新聞（5 條）&quot;">​</a></h2><ol><li><strong>CNBC (2026-05-16)</strong>：中國商務部稱川習會農業協議為「preliminary」，需盡快定案</li><li><strong>SCMP (2026-05-16)</strong>：分析師指「double-digit billions」多為舊承諾重包，增量有限</li><li><strong>S&amp;P Global (2026-05-14)</strong>：美國對華黃豆銷售年初至今年減 48%</li><li><strong>MalayMail/Reuters (2026-05-16)</strong>：伊拉克荷莫茲出口暴跌 90%（93M→10M 桶/月）</li><li><strong>WION (2026-05-16)</strong>：伊朗提議海峽「管理機制」，對合規船隻收費</li></ol><hr><h2 id="📊-情景分析" tabindex="-1">📊 情景分析 <a class="header-anchor" href="#📊-情景分析" aria-label="Permalink to &quot;📊 情景分析&quot;">​</a></h2><table tabindex="0"><thead><tr><th>情境</th><th>發生機率</th><th>價格影響</th><th>傳導機制</th></tr></thead><tbody><tr><td>中國 6 月下調黃豆 10% 關稅</td><td>60%</td><td>+3-5%（至 ~1,210-1,235¢）</td><td>私營壓榨廠恢復採購 → 短期需求增加</td></tr><tr><td>荷莫茲海峽 6 月重開</td><td>30%</td><td>-5-8%（至 ~1,080-1,120¢）</td><td>能源成本下降 → 農業成本壓力紓解 → 價格回落</td></tr><tr><td>海峽持續封閉 + 中國延遲關稅下調</td><td>40%</td><td>持平至 -2%（1,150-1,180¢）</td><td>能源成本高檔支撐底部 vs 需求疲軟壓制</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>TradingEconomics (2026-05-15): Soybeans 1,177 USd/Bu, WTI $105.42, Natural Gas $2.96, Urea $577</li><li>CNBC (2026-05-16): China signals tariff cuts, farm market access after Trump-Xi summit</li><li>SCMP (2026-05-16): Soybean counters — scope of China-US farm deal depends on math</li><li>S&amp;P Global (2026-05-14): US soybean sales to China fall 48% on year</li><li>MalayMail/Reuters (2026-05-16): Iraq Hormuz exports down 90%</li><li>WION (2026-05-16): Iran plans managed shipping route in Strait of Hormuz</li><li>Anadolu (2026-05-16): 78 ships redirected from Hormuz, CENTCOM</li><li>Farm Progress (2026-05-12): USDA crop progress 49% planted</li><li>AOL/Reuters (2026-05-16): China commerce ministry says deals are &quot;preliminary&quot;</li></ol>',36)])])}const m=r(o,[["render",n]]);export{c as __pageData,m as default};
